const tutorForm={name:'Parent / Guardian Name',student:'Student Name',subject:'Subject Needed',format:'Preferred Format',details:'Preferred days, time and additional notes',button:'Request a Tutor â†’'};
    const projectForm={name:'Full Name',student:'Institution',subject:'Academic Level',format:'Project Type',details:'Research topic, required support, deadline and additional details',button:'Request Academic Support â†’'};
    document.querySelectorAll('.tab').forEach(tab=>tab.addEventListener('click',()=>{document.querySelectorAll('.tab').forEach(t=>t.classList.remove('active'));tab.classList.add('active');const d=tab.dataset.form==='tutor'?tutorForm:projectForm;document.querySelector('label[for=name]').textContent=d.name;document.querySelector('label[for=student]').textContent=d.student;document.querySelector('label[for=subject]').textContent=d.subject;document.querySelector('label[for=format]').textContent=d.format;document.querySelector('label[for=details]').textContent=d.details;document.getElementById('submitBtn').textContent=d.button;document.getElementById('success').style.display='none';}));
    document.getElementById('requestForm').addEventListener('submit',e=>{e.preventDefault();document.getElementById('success').style.display='block';e.target.reset();});
    function handleContact(e){e.preventDefault();e.currentTarget.querySelector('.success').style.display='block';e.currentTarget.reset()};function handleNewsletter(e){e.preventDefault();e.currentTarget.innerHTML='<span style="color:#fff;font-weight:700">Thanks for joining us!</span>'};
    addEventListener('scroll',()=>document.querySelector('header').classList.toggle('scrolled',scrollY>4));
    const proprietor=document.createElement('figure');proprietor.className='proprietor';proprietor.innerHTML='<img src="fab-proprietor.jpeg" alt="Proprietor of Maffizz Edify, Educational Technologist"><figcaption class="proprietor-label"><strong>Meet the Proprietor</strong><span>Educational Technologist</span></figcaption>';document.querySelector('.hero-art').appendChild(proprietor);
    document.querySelectorAll('a[href*="wa.me"]').forEach(link=>link.href=link.href.replace('2348106365832','2347041059367'));document.querySelectorAll('.contact-item a[href*="wa.me"]').forEach(link=>link.textContent='0704 105 9367');

